// // This module implements a 2-bit binary counter with an enable signal. The counter counts from 0 to 3, and when the enable signal is low, the counter increments on the positive edge of the clock. If the counter reaches 3, it wraps around to 0. The counter should have a reset signal that resets it to 0 when deasserted.
module binary_counter (  
    input wire clk,  
    input wire reset,  
    input wire enable,  
    output reg [1:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 2'b00;  
        else if (enable)  
            count <= (count == 2'b11) ? 2'b00 : count + 1;  
    end  
endmodule
